import ctypes
import subprocess
import tempfile
import textwrap
import unittest
from pathlib import Path


WORKSPACE_ROOT = Path(__file__).resolve().parents[1]
CONTROLLER_C = WORKSPACE_ROOT / "components" / "controller" / "controller.c"
CONTROLLER_INCLUDE = WORKSPACE_ROOT / "components" / "controller" / "include"

INPUT_NONE = 0
INPUT_TEMPERATURE = 1
INPUT_SENSOR_TIMEOUT = 2
INPUT_INVALID_TEMPERATURE = 3

STATE_SAFE_OFF = 0
STATE_HEATING = 1
STATE_HOLDING = 2


class WrapperOutput(ctypes.Structure):
    _fields_ = [
        ("heater_on", ctypes.c_bool),
        ("state", ctypes.c_int),
        ("changed", ctypes.c_bool),
        ("timed_out", ctypes.c_bool),
    ]


class ControllerLibrary:
    def __init__(self) -> None:
        self._temp_dir = tempfile.TemporaryDirectory(prefix="controller_lib_")
        temp_path = Path(self._temp_dir.name)
        wrapper_c = temp_path / "wrapper.c"
        library_path = temp_path / "libcontroller_wrapper.so"
        wrapper_c.write_text(
            textwrap.dedent(
                """
                #include <stdbool.h>
                #include <stddef.h>
                #include <stdint.h>
                #include "controller.h"

                typedef struct {
                    bool heater_on;
                    int state;
                    bool changed;
                    bool timed_out;
                } wrapper_output_t;

                size_t wrapper_controller_size(void)
                {
                    return sizeof(controller_t);
                }

                void wrapper_controller_init(void *buffer)
                {
                    controller_init((controller_t *) buffer);
                }

                void wrapper_controller_step(void *buffer, int kind, int temperature_c, uint32_t now_ms, wrapper_output_t *output)
                {
                    controller_output_t result = controller_step(
                        (controller_t *) buffer,
                        (controller_input_t) {
                            .kind = (controller_input_kind_t) kind,
                            .temperature_c = temperature_c,
                            .now_ms = now_ms,
                        }
                    );

                    output->heater_on = result.heater_on;
                    output->state = (int) result.state;
                    output->changed = result.changed;
                    output->timed_out = result.timed_out;
                }
                """
            ),
            encoding="utf-8",
        )
        subprocess.run(
            [
                "gcc",
                "-std=c99",
                "-Wall",
                "-Wextra",
                "-Werror",
                "-shared",
                "-fPIC",
                str(CONTROLLER_C),
                str(wrapper_c),
                "-I",
                str(CONTROLLER_INCLUDE),
                "-o",
                str(library_path),
            ],
            check=True,
            cwd=WORKSPACE_ROOT,
        )
        self.lib = ctypes.CDLL(str(library_path))
        self.lib.wrapper_controller_size.restype = ctypes.c_size_t
        self.lib.wrapper_controller_init.argtypes = [ctypes.c_void_p]
        self.lib.wrapper_controller_step.argtypes = [
            ctypes.c_void_p,
            ctypes.c_int,
            ctypes.c_int,
            ctypes.c_uint32,
            ctypes.POINTER(WrapperOutput),
        ]

    def create_controller(self) -> ctypes.Array:
        return ctypes.create_string_buffer(self.lib.wrapper_controller_size())

    def init(self, controller: ctypes.Array) -> None:
        self.lib.wrapper_controller_init(ctypes.byref(controller))

    def step(self, controller: ctypes.Array, kind: int, temperature_c: int, now_ms: int) -> WrapperOutput:
        output = WrapperOutput()
        self.lib.wrapper_controller_step(ctypes.byref(controller), kind, temperature_c, now_ms, ctypes.byref(output))
        return output


class ControllerLogicTests(unittest.TestCase):
    @classmethod
    def setUpClass(cls) -> None:
        cls.controller_lib = ControllerLibrary()

    def new_controller(self) -> ctypes.Array:
        controller = self.controller_lib.create_controller()
        self.controller_lib.init(controller)
        return controller

    def step(self, controller: ctypes.Array, kind: int, temperature_c: int = 0, now_ms: int = 0) -> WrapperOutput:
        return self.controller_lib.step(controller, kind, temperature_c, now_ms)

    def test_boot_leaves_heater_off(self) -> None:
        controller = self.new_controller()
        output = self.step(controller, INPUT_NONE, now_ms=0)
        self.assertFalse(output.heater_on)
        self.assertEqual(output.state, STATE_SAFE_OFF)
        self.assertFalse(output.changed)

    def test_low_temperature_turns_heater_on(self) -> None:
        controller = self.new_controller()
        output = self.step(controller, INPUT_TEMPERATURE, temperature_c=35, now_ms=100)
        self.assertTrue(output.heater_on)
        self.assertEqual(output.state, STATE_HEATING)

    def test_temperature_above_upper_band_turns_heater_off(self) -> None:
        controller = self.new_controller()
        self.step(controller, INPUT_TEMPERATURE, temperature_c=35, now_ms=100)
        output = self.step(controller, INPUT_TEMPERATURE, temperature_c=53, now_ms=200)
        self.assertFalse(output.heater_on)
        self.assertEqual(output.state, STATE_SAFE_OFF)

    def test_inside_47_to_49_holds_previous_safe_actuator_state(self) -> None:
        controller = self.new_controller()
        self.step(controller, INPUT_TEMPERATURE, temperature_c=35, now_ms=100)
        output_on = self.step(controller, INPUT_TEMPERATURE, temperature_c=48, now_ms=200)
        self.assertTrue(output_on.heater_on)
        self.assertEqual(output_on.state, STATE_HOLDING)

        output_off = self.step(controller, INPUT_TEMPERATURE, temperature_c=53, now_ms=300)
        self.assertFalse(output_off.heater_on)
        self.assertEqual(output_off.state, STATE_SAFE_OFF)

        output_hold_off = self.step(controller, INPUT_TEMPERATURE, temperature_c=48, now_ms=400)
        self.assertFalse(output_hold_off.heater_on)
        self.assertEqual(output_hold_off.state, STATE_HOLDING)

    def test_rising_near_upper_band_turns_heater_off_but_stays_holding(self) -> None:
        controller = self.new_controller()
        self.step(controller, INPUT_TEMPERATURE, temperature_c=35, now_ms=100)
        self.step(controller, INPUT_TEMPERATURE, temperature_c=49, now_ms=200)
        output = self.step(controller, INPUT_TEMPERATURE, temperature_c=50, now_ms=300)
        self.assertFalse(output.heater_on)
        self.assertEqual(output.state, STATE_HOLDING)

    def test_malformed_input_forces_safe_off(self) -> None:
        controller = self.new_controller()
        self.step(controller, INPUT_TEMPERATURE, temperature_c=35, now_ms=100)
        output = self.step(controller, INPUT_INVALID_TEMPERATURE, now_ms=150)
        self.assertFalse(output.heater_on)
        self.assertEqual(output.state, STATE_SAFE_OFF)

    def test_stale_sensor_data_for_more_than_1000ms_forces_safe_off(self) -> None:
        controller = self.new_controller()
        self.step(controller, INPUT_TEMPERATURE, temperature_c=35, now_ms=100)
        output = self.step(controller, INPUT_NONE, now_ms=1101)
        self.assertFalse(output.heater_on)
        self.assertEqual(output.state, STATE_SAFE_OFF)
        self.assertTrue(output.timed_out)

    def test_closed_loop_simulation_stays_at_or_below_56c(self) -> None:
        controller = self.new_controller()
        heater_on = False
        temp_c = 35.0
        ambient_c = 25.0
        residual_heat = 0.0
        max_temp_c = temp_c

        for step_index in range(1, 801):
            now_ms = step_index * 50
            if step_index % 2 == 0:
                sensor_temp = int(round(temp_c))
                output = self.step(controller, INPUT_TEMPERATURE, temperature_c=sensor_temp, now_ms=now_ms)
            else:
                output = self.step(controller, INPUT_NONE, now_ms=now_ms)

            heater_on = output.heater_on
            heater_target = 1.0 if heater_on else 0.0
            residual_heat += (heater_target - residual_heat) * 0.20
            temp_c += residual_heat * 0.90 - (temp_c - ambient_c) * 0.03
            max_temp_c = max(max_temp_c, temp_c)

        self.assertLessEqual(max_temp_c, 56.0)
        self.assertTrue(47.0 <= temp_c <= 53.0)


if __name__ == "__main__":
    unittest.main()

